// FuzzJWSParseDetached has a different signature so gets its own test from FuzzJWSParse, but doesn't have much extra
func FuzzJWSParseDetached(f *testing.F) {
	f.Add("", []byte("test"))
	f.Add("a.b", []byte("test"))
	f.Add("a.b.c", []byte(nil))
	f.Add("eyJhbGciOiJIUzI1NiJ9..AAAA", []byte("test"))
	f.Add("eyJhbGciOiJIUzI1NiJ9.dGVzdA.AAAA", []byte("test"))
	f.Fuzz(func(t *testing.T, sig string, payload []byte) {
		// We are only checking this doesn't panic
		_, _ = jose.ParseDetached(sig, payload, allSignatureAlgorithms)
	})
}
